#!/usr/bin/env python3
"""
Test script to reproduce the language prefix issue and verify the fix.
"""

import markdown
from pymdownx.highlight import HighlightExtension


def test_current_behavior():
    """Test the current behavior with default settings."""
    print("=== Testing Current Behavior ===")

    md = markdown.Markdown(
        extensions=[HighlightExtension()],
        extension_configs={
            'pymdownx.highlight': {
                'use_pygments': False  # Use JS highlighting mode
            }
        }
    )

    # Test basic code block
    source = "```python\nprint('hello')\n```"
    result = md.convert(source)
    print("Input:", repr(source))
    print("Output:", result)
    print("Contains 'language-python':", 'language-python' in result)
    print()


def test_no_prefix_desired():
    """Test the desired behavior with empty prefix."""
    print("=== Testing Desired Behavior (Empty Prefix) ===")

    md = markdown.Markdown(
        extensions=[HighlightExtension()],
        extension_configs={
            'pymdownx.highlight': {
                'use_pygments': False,  # Use JS highlighting mode
                # TODO: Add language_prefix option here once implemented
            }
        }
    )

    # Test basic code block
    source = "```python\nprint('hello')\n```"
    result = md.convert(source)
    print("Input:", repr(source))
    print("Output:", result)
    print("Should contain 'python' without 'language-' prefix")
    print()


def test_custom_prefix():
    """Test custom prefix behavior.""" 
    print("=== Testing Custom Prefix ===")

    md = markdown.Markdown(
        extensions=[HighlightExtension()],
        extension_configs={
            'pymdownx.highlight': {
                'use_pygments': False,  # Use JS highlighting mode
                # TODO: Add language_prefix option here once implemented
            }
        }
    )

    # Test basic code block
    source = "```python\nprint('hello')\n```"
    result = md.convert(source)
    print("Input:", repr(source))
    print("Output:", result)
    print("Should contain custom prefix + language")
    print()


if __name__ == "__main__":
    test_current_behavior()
    test_no_prefix_desired() 
    test_custom_prefix()

